var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"아이구, 이게 누구신가? 세계를 구한 영웅, 우리 딸이잖아?","JPN":"おやおや、誰かと思えば、世界を救った英雄、我が娘じゃないか？","ENG":"Well, look who it is! It's the hero who saved the world, my daughter!","TWN":"哎呀，瞧瞧這是誰？這不是我的女兒，拯救世界的英雄嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하, 하하……. 오랜만에 찾아 뵙네요. 아빠.","JPN":"ハ、ハハ……お久しぶりです。お父さん。","ENG":"Ha, ha ha... It's been a while, Dad.","TWN":"哈，哈哈……爸爸好久不見。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"피, 피난 지구 쪽 쉘터는 어떠세요……?","JPN":"ひ、避難地区のシェルターはどう？","ENG":"H-how's the refugee district...?","TWN":"庇，庇護中心那邊的生活怎麼樣……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐 불편한 건 없어요? 음식은 잘 배급되는 거 맞죠? 카린 양이 특별히 신경 써준다고는 했는데…….","JPN":"何か不便なところは？　食料はちゃんと配給されてる？　カリンさんが気を遣ってくれるって言っていたけど……","ENG":"Anything you need? Are you getting enough provisions? Karin told me she'd take special care of you...","TWN":"有沒有哪裡不方便的？有按時候拿到食物吧？卡琳說過會特別關照的……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"하하. 걱정하지 말라구, 딸?","JPN":"はは、大丈夫だ。","ENG":"Ha ha. Don't you worry.","TWN":"哈哈，不用擔心，女兒。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"말도 없이, 생환 가능성 5%의 미친 작전에 덜컥 지원하더니…….","JPN":"相談もなしに、生還確率5％のイカレた作戦に突然志願して……","ENG":"You sneakily apply for a crazy operation with a 5% survival chance...","TWN":"你沒說一聲就報名參加生還率只有5%的作戰……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"죽었는지 살았는지 연락도 없다가, 이제서야 난데없이 나타난 딸 덕분에 잘 먹고 잘 살고 있으니까.","JPN":"生死がわからないまま連絡もずっとなし、と思っていたらいきなり現れた娘のおかげでちゃんと贅沢に暮らせているぞ。","ENG":"Leave us in the dark, making us wonder if you're even alive or dead, and suddenly reappear. But sure, the refugee district is fine.","TWN":"然後就沒消沒息，是死是活都不知道，現在才突跑出來現……放心，我們過得很好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아이 참. 또 비꼬기 시작이시네. 이렇게 살아 돌아왔으니까, 됐잖아요~","JPN":"もう、また嫌味が始まった。こうして生きて帰ってきたんだからいいじゃない～","ENG":"Oh, c'mon. Again with the passive aggression. I'm back alive. Isn't that what matters?","TWN":"討厭，你又在挖苦我，反正我平安回來就好啦～"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"애초에 엄마 아빠가 반대할 걸 아니까 말하지 않았던 거라고요.","JPN":"そもそもお母さんやお父さんは反対するってわかっていたから、言わなかったの。","ENG":"I didn't tell you because I knew you and Mom would never agree to it.","TWN":"我知道你們一定會反對，所以才沒說的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러고보니, 엄마는요?","JPN":"そういえば、お母さんは？","ENG":"Speaking of, where is Mom?","TWN":"不過，怎麼沒看到媽媽？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"하하, 나랑 달리 엄마가 속이 좀 좁잖아?","JPN":"はは、お父さんと違って、お母さんは心が狭いだろ？","ENG":"Ha ha, unlike me, she's a bit stubborn.","TWN":"哈哈，你媽和我不一樣，她很小心眼。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"네가 그 작전에 참여하겠다고 나간 뒤로 다시는 얼굴 안 보겠다고 고집을 부리더구나.","JPN":"お前がその作戦に参加するって言って出て行って以来、二度と顔を合わせたくないと意地を張っているんだ。","ENG":"She was adamant about not seeing you after you participated in that operation.","TWN":"知道你參加那個作戰後，她就很生氣，說要和你斷絕母女關係。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"알잖아? 네가 용병일 하는 것도 싫어하던 사람이야.","JPN":"わかっているだろう？　お母さんはお前が傭兵の仕事をするのも嫌がっていたんだ。","ENG":"You know how she was also against you being a mercenary.","TWN":"你也知道，她一直很不喜歡你當傭兵。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에효, 우리 엄마도 참 여전하네.","JPN":"はぁ、お母さんは相変わらずなのね。","ENG":"Geez, she hasn't changed a bit, has she?","TWN":"哀，我媽還是老樣子呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"요즘 같은 세상에 용병이 얼마나 프로페셔널한 대접을 받는데요.","JPN":"最近の世の中では、傭兵はプロフェッショナルの待遇を受けるっていうのに。","ENG":"She should know how well mercenaries are treated these days.","TWN":"現在這個世道，傭兵的待遇不知道多好呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그리고 저 정도면 군의 의뢰도 접수 받는 최고급 용병이라구요, 엣헴!","JPN":"それに、私は軍からの依頼もくるほど、最高ランクの傭兵なんだから、えっへん！","ENG":"And I'm one of the top mercenaries that accepts contracts from the military, too!","TWN":"而且，我這種可是能夠接受部隊委託的最高級傭兵呢，嘿嘿！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그래, 우리 딸이 세상을 구할 정도로 좀 대단하긴 하지.","JPN":"そうだな、お前は世界を救えるくらいすごいんだもんな。","ENG":"Yeah, I guess you ARE the savior of the world.","TWN":"沒錯，我們女兒確實厲害，還能拯救世界呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그래도 다시는 그런 짓 하지 말거라. 너 아니라도, 분명 대신할 사람이 있었을 거야.","JPN":"でも二度とあんなことはしないでくれ。お前がやらずとも、きっとそれをやってくれる人はいたはずだ。","ENG":"Still, don't do something like that again. Even if you hadn't joined the operation, someone else would've stepped in.","TWN":"但是下不為例，又不是非你不可，還有其他人嘛？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"굳이 너까지 희생할 필요는 없었잖니?","JPN":"わざわざお前までが犠牲になる必要はなかっただろう？","ENG":"There was no need for you to sacrifice yourself.","TWN":"不一定非要犧牲你吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 그게 그러니까, 그땐 상황이 너무 급박해서…….","JPN":"ハハ、だからさ、あの時はあまりにも緊急だったから……","ENG":"Ha ha, well, everything was so urgent back then...","TWN":"哈哈，這個嘛，因為當時的情況很緊急……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그래서? 아이를 전쟁터에 몰아 넣는게 당연하다는 거냐?","JPN":"それで？　子どもを戦争に追い込むことが当たり前だと言うのか？","ENG":"So? Having a child fight in a war is okay?","TWN":"所以呢？把孩子推入戰場是理所當然的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그동안 연락도 안 되고…… 우리가 얼마나 걱정했는 줄 알기나 해?","JPN":"その間連絡も付かず……私たちがどれだけ心配したことか。","ENG":"We couldn't reach you all this time... Do you even know how worried we were?","TWN":"而且這期間都聯繫不上……你知道我們有多擔心嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"애초에 이 세계가 이렇게 된 건 너희의 잘못이 아니야. 우리 같은 어른들의 잘못이지.","JPN":"そもそもこの世界がこうなったのはお前たちのせいじゃない。私たち大人のせいだ。","ENG":"It isn't your fault that the world ended up this way. We adults are responsible for that.","TWN":"當初這個世界會變成這樣又不是你們的錯，是我們這些大人犯下的錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그러니까, 너희 같은 아이들이 책임질 필요가 없어!","JPN":"だから、お前たちのような子どもが背負う必要はないんだ！","ENG":"So, children like you don't have to carry the weight of it!","TWN":"所以，不需要讓孩子們去承擔後果！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"……휴우, 아빠.","JPN":"……はぁ、お父さん。","ENG":"...*Sigh* Dad.","TWN":"……哎呀，爸爸。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"제가 아는 어떤 <color=#ffd34c>친구</color>는 입버릇처럼 말하곤 해요.","JPN":"私の<color=#ffd34c>知り合い</color>は口癖のようにこう話すの。","ENG":"There's a <color=#ffd34c>friend</color> I know, who used to say...","TWN":"我認識的一個<color=#ffd34c>朋友</color>曾經和我說過。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무리 멸망해가는 세상이라고 해도, 살 수 있을 때까지 살아야 한다고…….","JPN":"滅びゆく世界だとしても、生きられるところまでは生き抜かなければならないって……","ENG":"Even in a dying world, you have to live as long as you can.","TWN":"就算是瀕臨滅亡的世界，也要盡最大努力活下去……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"최선을 다해서 할 수 있는 일을 찾아야 한다고요.","JPN":"全力で自分にできることを見つけなければならないって。","ENG":"We have to do our best to find a way.","TWN":"我想盡我所能找到我能做的事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"전 아빠나 엄마가 생각하는 것만큼 어리지 않아요. 제 일은 제가 책임질 수 있어요.","JPN":"私はお父さんやお母さんが思っているほど、もう子どもじゃないよ。自分の行動の責任は自分で取れる。","ENG":"I'm not as young as you or Mom might think. I can be responsible with my job.","TWN":"我不像爸媽想得那麼幼小，我的事我自己可以負責。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저랑 같이 작전을 수행한 내 고용주도 나랑 같은 나이인 걸요?","JPN":"私と一緒に作戦を遂行したクライアントも私と同い年なんだよ？","ENG":"Even my employer, with whom I worked in the operation, is the same age as me.","TWN":"和我一起執行作戰的雇主也跟我同年紀呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"고용주? 저번에 소령이라고 하지 않았었니?","JPN":"クライアント？　以前少佐だって言ってなかったか？","ENG":"Your employer? Didn't you say she was a Major before?","TWN":"雇主？上次不是說是少校嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그, 그 나이에 벌써 소령을 달았다고?","JPN":"そ、その年齢でもう少佐なのか？","ENG":"S-she's your age, and is already a Major?","TWN":"年，年紀輕輕就當少校啦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 뿐만이 아니에요. 다른 세계…… 아니, 다른 곳에서도 저랑 비슷한 나이대의 카운터가 사람을 지키기 위해 싸우고 있어요.","JPN":"それだけじゃないよ。他の世界……いや、他の場所でも私と同年代のカウンターがみんなを守るために戦ってる。","ENG":"Not just that. In a different world–I mean, in a different place, there are Counters my age who are fighting to protect people.","TWN":"不僅如此，在其他世界……不，在其他地方也有和我年紀相仿的制裁者，大家都在為守護他人而戰。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"사람을 지킬 힘을 가지고 있는데, 그 힘으로 사람을 구하는 게 잘못된 건가요?","JPN":"人を助けられる力があるのに、その力で人を助けるのは間違っているの？","ENG":"If they have the power to protect people, is it so wrong of them to actually use it?","TWN":"既然擁有可以守護他人的力量，就用這個力量去拯救別人，這有什麼錯呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후후, 그리고 아빠 딸은 실제로 멸망할 뻔한 세상을 구하기도 했다고요?","JPN":"ふふ、それに、お父さんの娘は実際に滅びそうになった世界を助けたんだから。","ENG":"Heh heh, and your daughter, I might add, saved a world that almost got destroyed.","TWN":"呵呵，而且你的女兒可是真的拯救了差點滅亡的世界喔。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이쯤이면 자부심을 가져도 좋지 않을까요?","JPN":"そろそろ誇らしく思ってくれてもいいんじゃない？","ENG":"That sounds like something you can be proud of, no?","TWN":"這樣應該足以讓你引以為傲吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그렇구나, 아직 어린 아이라고 생각했는데. 우리 딸이 벌써 이렇게 컸구나.","JPN":"そうだな、まだ子どもだと思っていたのに。いつの間にか大きくなったんだな。","ENG":"Right. I just imagined you as a little kid, but you've grown up.","TWN":"呵呵，我以為你還是小孩子，沒想到我的女兒都長這麼大啦。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그래, 알겠다. 네 뜻이 그렇다면 더 이상 간섭하지 않으마.","JPN":"わかった。お前がそう言うなら、もう口出しはしない。","ENG":"Fine. If that's what you're trying to do, I won't interfere.","TWN":"好吧，既然你執意如此，那我不會再干涉了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"하지만 너무 열심히는 하지 말거라. 다치지도 말고. 힘들겠다 싶으면 적당히 도망쳐.","JPN":"でもあまり頑張りすぎるなよ。ケガもするな。辛くなったら適当に逃げるんだ。","ENG":"But don't work too hard. Don't get hurt. If it looks dangerous, just run away.","TWN":"但不要拼命過頭，也不要受傷，如果覺得累，那就逃吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"도망친다고…… 아무도 그걸 너희 책임이라고 탓하지 않을 테니까.","JPN":"逃げたからといって……誰もお前たちのせいにして責めたりはしない。","ENG":"No one... No one's going to blame you for running away.","TWN":"就算逃跑……也沒有人會責怪你們的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이, 알고 있어요. 그거야 말로 제가 제일 잘하는 걸요?.","JPN":"はいはい、わかってるよ。それこそ、私が一番得意なことだしね！","ENG":"Pshh, I know. That's what I do best.","TWN":"好啦，我知道，我最清楚那一點好嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아빠 딸 답게…… 어떤 일에도 대충 최선을 다하는 거.","JPN":"お父さんの娘らしく……どんなことに対してもテキトーに最善を尽くすのは。","ENG":"Like father like daughter... Give everything your best, sometimes.","TWN":"誰叫我遺傳爸爸……無論什麼事都會適當地拼命去做。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"후후, 그래.","JPN":"ふふ、そうだ。","ENG":"Ha ha. Right.","TWN":"呵呵，很好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"엄마한테는 다음에는 꼭 만나자고 얘기해보마.","JPN":"お母さんには次は会ってみるように言っておくよ。","ENG":"I'll try to convince your mom to meet you next time.","TWN":"我去勸勸你媽，讓她別再跟你賭氣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"……그리고 그 옷 좀 어떻게 안 되겠니?","JPN":"……あと、その服装はなんとかならないのか？","ENG":"...Also, can't you do anything about your clothes?","TWN":"……還有，你衣服能不能整理一下？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"다 큰 처자가 칠칠 맞게 그게 뭐야? 속옷이 다 보이잖아?","JPN":"いい歳をした娘が、だらしないぞ。下着が丸見えだ。","ENG":"Your underwear is showing. You're not a child anymore, can you button up or something?","TWN":"都這麼大的人了，衣服也不穿好，內衣都被看到了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 아하하. 괜찮아요. 괜찮아.","JPN":"ア、アハハ、大丈夫、大丈夫。","ENG":"Ahh, ah ha ha. It's fine.","TWN":"喔，哈哈哈！沒關係啦，沒事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어차피 저희 팀은 다 여자밖에 없거든요.","JPN":"どうせ私たちのチームには女しかいないから。","ENG":"Our team is all women anyway.","TWN":"反正我們隊裡都是女生。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제야 나타나났군요, 시영 씨!","JPN":"遅いですよ、シノンさん！","ENG":"Shiyoung! Finally!","TWN":"你怎麼現在才來，時雨！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"지금이 몇 시인 줄 아세요? 오늘은 중요한 날이니까, 늦지 말라고 몇 번이나 말했잖아요!","JPN":"今何時だと思っているんですか？　今日は大事な日だから遅れないようにとあれだけ言ったのに！","ENG":"Do you realize what time it is? I told you, today's an important day, so don't be late!","TWN":"你知道現在幾點嗎？我說過今天是很重要的日子，絕對不能遲到！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이, 너무 그렇게 화내지 말아요, 고작 10분 늦은 걸요.","JPN":"またまた～そんなに怒らないでくださいよ、たった10分遅れただけじゃないですか。","ENG":"Jeez, don't get too fussy. I'm only 10 minutes late.","TWN":"哎呀，不要生氣嘛，我不過遲到十分鐘而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"꼭 들렸다 와야 할 때가 있어서 늦은 거라고요.","JPN":"どうしても寄らないといけないところがあって、遅れたんですよ。","ENG":"I had to make a detour.","TWN":"因為我剛必須先去個地方，所以才會晚到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흥! 또 쓸데없이 고양이랑 놀아주고 온 거겠죠. 안 봐도 뻔하다고요.","JPN":"フン！　どうせまた猫とじゃれ合ってたんでしょう。見なくてもわかります。","ENG":"Hmph! I bet you were just playing with cats again. It's obvious.","TWN":"哼！想也知道，一定又是去找貓玩了吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라, 어떻게 알았지? 역시 카린 양은 똑똑하다니까요.","JPN":"あら、どうしてわかったんです？　さすがはカリンさん、賢いですね。","ENG":"Oh, how did you know? You're so smart, Karin.","TWN":"哇，你怎麼知道？卡琳果然很聰明呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어때요? 카린 양도 고양이처럼 착하다, 착하다 하고 잔뜩 쓰다듬어 드릴까요?","JPN":"どうです？　カリンさんも猫みたいに、よしよししてあげましょうか？","ENG":"I can pet you like a cat and say \\"Who's a good girl\\" to you. What do you say?","TWN":"怎麼樣？要不我也像摸貓一樣摸摸你？說你好乖？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"으악! 고양이 털 묻으니까, 저리 가서 손부터 씻고 와요!","JPN":"きゃっ！　猫の毛が付くから、まずは手を洗ってきてください！","ENG":"Ahhh! You're going to get cat hair on me. Go wash your hands first!","TWN":"走開啦！貓毛會沾到我身上，你先去洗手！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"으휴, 저 덤앤더머는 오늘도 조용할 날이 없네.","JPN":"まったく、あの二人はいつもうるさいわね。","ENG":"Ugh, dumb and dumber over there are always so loud.","TWN":"哀，傻瓜二人組今天也不得閒呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그래서 브리핑은 대체 언제 시작할 거야, 잔소리꾼?","JPN":"それで、ブリーフィングはいつ始まるの、小言さん？","ENG":"So, when are you gonna start the briefing, nagger?","TWN":"什麼時候才要開始報告啦，嘮叨鬼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"다들 기다리고 있다고.","JPN":"みんな待っているのよ。","ENG":"We're all waiting.","TWN":"大家都在等你欸。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흠, 크흠! 또 쓸데없이 시영 씨의 페이스에 말려들고 말았군요.","JPN":"ふむ、こほん！　また無駄にシノンさんのペースに飲まれてしまいましたね。","ENG":"A-ahem! I got caught up in Shiyoung's nonsense again.","TWN":"咳咳！又被時雨岔開話題。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"다들 서두르도록 해요, 이렇게 노닥거릴 시간이 없다구요.","JPN":"皆さん、急ぎましょう。こうして遊んでいる暇はありません。","ENG":"Let's hurry, everyone. There is no time to sit around.","TWN":"那就趕緊開始吧，沒時間說這些有的沒的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……크로스로드 작전의 성공 후, 우리 세상은 약 20년의 유예를 얻을 수 있었습니다.","JPN":"……クロスロード作戦が成功し、私たちの世界は約20年間の猶予を得ました。","ENG":"...After the success of Operation Crossroads, our world has earned 20 years of extra time.","TWN":"……十字路口作戰成功後，我們世界多爭取到大約二十年的時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러나 여전히 세상의 멸망을 막기에는 기술도, 자원도 부족한 상황이죠.","JPN":"しかし相変わらず、世界の滅亡を食い止めるには、技術も資源も足りていません。","ENG":"However, we lack the technology and resources to stop the world from ending.","TWN":"但我們的技術和資源依舊不足，不足以阻擋世界的滅亡。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"따라서 우리 델타 세븐은 새로운 기술과 자원 확보를 위해, 새로운 작전을 시작하려 합니다!","JPN":"そこで、我々デルタセブンは新たな技術と資源の確保のために、新しい作戦を開始しようと思います！","ENG":"Therefore, in order to secure new technology and resources, Delta Seven is commencing a new operation!","TWN":"因此，我們第七三角洲部隊為了取得全新的技術和資源，將展開新的作戰！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우선, 전 세계 각지에 퍼져있는…….","JPN":"第一に、世界各地に分散している……","ENG":"First, we will go collect...","TWN":"首先，要把散落在各地的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에휴……. 역시 카린 양은 대단하네.","JPN":"まったく……さすがカリンさんだな。","ENG":"Well... Karin never fails to impress.","TWN":"哇……卡琳果然厲害。"},"stage":{"bg":"BLACK","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이쯤 했으면…… 남은 20년은 그냥 하루하루 편하게 사는 것도 나쁘지 않을 텐데…….","JPN":"もう十分頑張ったし……残りの20年は毎日を気楽に生きてもいいはずなのに……","ENG":"She's already accomplished so much... It wouldn't be so bad to just live the remaining 20 years in peace...","TWN":"現在這樣……在剩下的二十年舒服過日子也不錯說……"},"stage":{"bg":"BLACK","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래, 뭐 어쩔 수 없나.","JPN":"まぁ、仕方ないか。","ENG":"Well, I guess this is just her.","TWN":"能怎麼辦呢？"},"stage":{"bg":"BLACK","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"약간 어설프긴 해도, 포기하지 않고 끝까지 최선을 다하는 게 카린 양의 매력이니까.","JPN":"少し不器用だけど、諦めずに最後まで全力でやるのが、カリンさんの魅力だものね。","ENG":"She may fumble a little, but not giving up and trying her best until the end is her charm.","TWN":"雖然有點傻氣，但不放棄，拚到最後一刻就是卡琳的魅力。"},"stage":{"bg":"BLACK","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그리고 결과가 어쨌든, 최선을 다하는 사람을 돕고 싶은 건 이상한 일이 아니잖아?","JPN":"そして結果はどうであれ、全力で頑張っている人を助けたくなるのは、別に変じゃないでしょ？","ENG":"And whatever happens, it's not so weird to want to help someone trying their best.","TWN":"而且，無論結果如何，想幫助努力的人也沒什麼好奇怪的吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래서…… 첫 번째 탐사 작전에 참가할 지원자를 모집하려고 합니다만…….","JPN":"というわけで……最初の探索作戦に参加する志願者を募集したいのですが……","ENG":"So... I'm going to start recruiting people to join the first expedition operation...","TWN":"所以……我需要招募人員進行首次探索作戰……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"작전에 참가하고 싶으신 분 있나요?","JPN":"作戦に参加したい方はいらっしゃいますか？","ENG":"Does anyone want to join the operation?","TWN":"有人想參加作戰嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저요, 저요! 카린 양, 저요, 저……!","JPN":"私、私！　カリンさん、私やります、私……！","ENG":"I do! I do! Karin, me! I do...!","TWN":"我，我！卡琳，選我選我……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……크읏! 거절합니다, 시영 씨는 빼고요!","JPN":"……くっ！　お断りします、シノンさん以外で！","ENG":"...Kgh! I refuse. Not you, Shiyoung!","TWN":"……咳！我拒絕，還有其他人嗎！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이, 섭섭하게 왜 그래요, 카린 양?","JPN":"またまた～冷たいな、カリンさんは！","ENG":"Oh, why so grumpy, Karin?","TWN":"哎呀，你怎麼這樣傷我的心，卡琳？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이래봬도 저만한 프로페셔널…… 꽤 찾기 힘들다고요?","JPN":"なんだかんだ言っても私ほどのプロフェッショナルは……そういませんよ？","ENG":"It's hard to find someone as professional as me, you know?","TWN":"像我這樣的專業人士，可是打著燈籠都很難找的喔？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"걱정마세요. 보수만 알맞게 주신다면야……","JPN":"心配いりません。成果に見合った報酬さえもらえるなら……","ENG":"Don't worry. As long as you pay me...","TWN":"不用擔心，只要給夠報酬……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"언제든 최선을 다해 적당히~ 어울려 드릴테니까요.","JPN":"いつでも最善を尽くして、テキトーにお付き合いしますから。","ENG":"I'll try my best to be mediocre.","TWN":"無論何時，我都會適當地～拼命的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};